// CLICKABLE TEXT
function click(...parts) {
  let output = "";

  parts.forEach((p, i) => {
    // Plain text
    if (typeof p === "string") {
      output += p;
    }

    // Colored text
    else if (p.type === "color") {
      output += `<span style="color:${p.color};">${p.text}</span>`;
    }

    // Clickable command
    else if (p.type === "cmd") {
      let id = "cmd_" + Date.now() + "_" + i;

      output += `<a href="#" id="${id}" style="
        display:inline;
        width:auto;
        color:${p.color || 'cyan'};
        text-decoration:none;
        border:none;
        padding:0;
        margin:0;
        cursor:pointer;
      ">${p.text}</a>`;

      setTimeout(() => {
        let el = document.getElementById(id);
        if (el) {
          el.onclick = (e) => {
            e.preventDefault();
            gwc.connection.send(p.command, true);
          };
        }
      }, 0);
    }

    // Clickable function
    else if (p.type === "func") {
      let id = "func_" + Date.now() + "_" + i;

      output += `<a href="#" id="${id}" style="
        display:inline;
        width:auto;
        color:${p.color || 'cyan'};
        text-decoration:none;
        border:none;
        padding:0;
        margin:0;
        cursor:pointer;
      ">${p.text}</a>`;

      setTimeout(() => {
        let el = document.getElementById(id);
        if (el) {
          el.onclick = (e) => {
            e.preventDefault();
            p.onClick();
          };
        }
      }, 0);
    }
  });

  gwc.output.append(output);
  gwc.output.replace(output, output);
}
